"use strict";(globalThis.webpackChunkblog_page=globalThis.webpackChunkblog_page||[]).push([[459],{6174(e,a,t){t.r(a),t.d(a,{assets:()=>d,contentTitle:()=>r,default:()=>c,frontMatter:()=>i,metadata:()=>n,toc:()=>h});var n=t(1691),s=t(2615),o=t(7545);const i={slug:"TakingAIForward",title:"Taking AI Forward",authors:["prakash-hegade"]},r=void 0,d={authorsImageUrls:[void 0]},h=[];function l(e){const a={p:"p",...(0,o.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(a.p,{children:"I am talking about the time when purchases happened face-to-face. Oh wait, they still do happen. A product hunt today has become easy. Purchases can now happen online. Reviews, recommendations, and price comparisons have always been there. AI today is helping to take the next leap. That already gives us enough information to decide what has stayed and what has changed. Did the markets disappear? No. The way we make decisions has changed. As we can see, markets have stayed, products have stayed, and human needs have stayed. The speed, scale and the way we access the information has changed and that leading to how we take the decisions."}),"\n",(0,s.jsx)(a.p,{children:"Taking a photo involved film rolls. After all the photos were taken, we had to take the roll to a studio and wait a few days to see the results. Then digital cameras arrived and photos could be seen instantly. Now, smartphones capture pictures and also give us options to enhance them. Where are the film rolls and dark rooms today by the way? We hardly see the postman, but more delivery riders are on the roads. We don\u2019t need to ask for directions anymore. We have GPS systems, but we still rely on asking strangers for directions rather than completely relying on technology."}),"\n",(0,s.jsx)(a.p,{children:"The written letters once took days to deliver. Parcel delivery still takes days. Searching for information once required long exploration. Real research still needs long investigation. Learning a new skill once required finding the right teacher. True mastery still requires guidance and practice. Sending money once required visiting a bank. Trust in transactions still takes time to build. Booking a ticket for a journey once required standing in long queues. Even now, travel takes its own time."}),"\n",(0,s.jsx)(a.p,{children:"Do you see all these things do not come with a single pattern? Or do they? AI is attempting to do that. When people speak about artificial intelligence, the conversation usually happens around algorithms, computing power, and data.  Most are still trying to figure out what AI is and how it looks like. We all know it has benefits. These are undeniably important, and they form much of what we see on the surface. Along with faster computations, humans must decide the direction that AI action must move towards."}),"\n",(0,s.jsx)(a.p,{children:"Everybody brings their own pool of experiences and perspectives to the table, and from that they attempt to place their predictions about where AI is heading. Cautious, optimistic, and speculative are the kinds of discussions we are having around AI. Individual predictions alone do not shape the direction of AI. The AI market is rather influenced and grounded by the needs and demands of society. As technology has aided in solving real problems of people and organizations, AI technology will continue to do the same. While opinions and forecasts create discussion, it is ultimately the demands of society, industries, and everyday users that determine where AI advances and where it finds its place."})]})}function c(e={}){const{wrapper:a}={...(0,o.R)(),...e.components};return a?(0,s.jsx)(a,{...e,children:(0,s.jsx)(l,{...e})}):l(e)}},7545(e,a,t){t.d(a,{R:()=>i,x:()=>r});var n=t(9471);const s={},o=n.createContext(s);function i(e){const a=n.useContext(o);return n.useMemo(function(){return"function"==typeof e?e(a):{...a,...e}},[a,e])}function r(e){let a;return a=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:i(e.components),n.createElement(o.Provider,{value:a},e.children)}},1691(e){e.exports=JSON.parse('{"permalink":"/vled/TakingAIForward","editUrl":"https://github.com/vicharanashala/vled/tree/master/blog-page/blog/2026-03-14-TakingAIForward/index.md","source":"@site/blog/2026-03-14-TakingAIForward/index.md","title":"Taking AI Forward","description":"I am talking about the time when purchases happened face-to-face. Oh wait, they still do happen. A product hunt today has become easy. Purchases can now happen online. Reviews, recommendations, and price comparisons have always been there. AI today is helping to take the next leap. That already gives us enough information to decide what has stayed and what has changed. Did the markets disappear? No. The way we make decisions has changed. As we can see, markets have stayed, products have stayed, and human needs have stayed. The speed, scale and the way we access the information has changed and that leading to how we take the decisions.","date":"2026-03-14T00:00:00.000Z","tags":[],"readingTime":2.48,"hasTruncateMarker":true,"authors":[{"name":"Prakash Hegade","title":"Instructional Systems Scientist","url":"https://linkedin.com/in/prakash-hegade-16879917","page":{"permalink":"/vled/authors/all-prakash-hegade-articles"},"socials":{"linkedin":"https://www.linkedin.com/in/prakash-hegade-16879917/"},"imageURL":"https://media.licdn.com/dms/image/v2/C5103AQEJcWXDC2k-0g/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1561842283995?e=1772064000&v=beta&t=FOJtDBcByZx7zgdKXTWTm1L18Czhcn3aENIb7wW66UY","key":"prakash-hegade"}],"frontMatter":{"slug":"TakingAIForward","title":"Taking AI Forward","authors":["prakash-hegade"]},"unlisted":false,"nextItem":{"title":"Can AI Be Conscious?","permalink":"/vled/CanAIBeConscious"}}')}}]);